  ('social-worker-moex-06990', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '某專職員工達30人以上的組織，正在擬議新的人力資源管理規章，下列那項不符合「性別工作平等法」 的規定？', '["女性員工因生理日導致工作有困難者，得請生理假一日，但不得併入病假計算", "女性員工為撫育未滿三歲子女，得向機構請求減少工作一小時，減少工作之時間不得請求報酬", "女性員工於分娩前後，雇主應使其停止工作，給予產假八星期", "男性員工於配偶分娩時，雇主應給予陪產假三日"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "861375f44ec1", "answer_pdf_sha1": "a6b708cb0119", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
